180	        ]),
181	        _ => None,
182	    }
183	}
184	
185	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
186	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
187	    let required = match rbtdrm_required_colophons(fixture) {
188	        Some(r) => r,
189	        None => {
190	            return Err(format!(
191	                "rbtd: unknown fixture '{}' — not registered in manifest",
192	                fixture
193	            ));
194	        }
195	    };
196	    for colophon in required {
197	        let found = manifest.split_whitespace().any(|token| token == *colophon);
198	        if !found {
199	            return Err(format!(
200	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
201	                colophon, fixture
202	            ));
203	        }
204	    }
205	    Ok(())
206	}
