478	/// Set `RBRR_DEPOT_MONIKER` in rbrr.env to `moniker` and commit. Cases 2-3
479	/// use this to install a moniker that drives `RBDC_DEPOT_PROJECT_ID` via
480	/// kindle derivation. The commit is separate from the throwaway-prefix
481	/// commit so the audit trail shows the moniker landing as its own pace.
482	fn rbtdrp_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
483	    let rbrr = root.join(RBTDRP_RBRR_FILE);
484	    let content = std::fs::read_to_string(&rbrr)
485	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
