929	    if probe_dir.exit_code != 0 {
930	        return rbtdre_Verdict::Fail(format!(
931	            "access-probe director exit {}\n{}",
932	            probe_dir.exit_code, probe_dir.stderr
933	        ));
934	    }
935	
936	    // Divests in reverse order.
937	    let divest_dir = match rbtdrp_invoke_logged(
938	        ctx,
939	        RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
940	        &[RBTDRP_IDENTITY_DIRECTOR],
941	        &[],
942	        dir,
943	        "divest-director",
944	    ) {
945	        Ok(r) => r,
946	        Err(e) => return rbtdre_Verdict::Fail(format!("divest director: {}", e)),
947	    };
948	    if divest_dir.exit_code != 0 {
949	        return rbtdre_Verdict::Fail(format!(
950	            "divest director exit {}\n{}",
951	            divest_dir.exit_code, divest_dir.stderr
952	        ));
953	    }
954	    if director_canonical.exists() {
955	        return rbtdre_Verdict::Fail(format!(
956	            "director canonical RBRA still present after divest: {} \
957	             (BBAAN divest-deletes-production-RBRA contract violated)",
958	            director_canonical.display()
959	        ));
960	    }
961	
962	    let divest_ret = match rbtdrp_invoke_logged(
963	        ctx,
964	        RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
965	        &[RBTDRP_IDENTITY_RETRIEVER],
966	        &[],
967	        dir,
968	        "divest-retriever",
969	    ) {
970	        Ok(r) => r,
971	        Err(e) => return rbtdre_Verdict::Fail(format!("divest retriever: {}", e)),
972	    };
973	    if divest_ret.exit_code != 0 {
974	        return rbtdre_Verdict::Fail(format!(
975	            "divest retriever exit {}\n{}",
976	            divest_ret.exit_code, divest_ret.stderr
977	        ));
978	    }
979	    if retriever_canonical.exists() {
980	        return rbtdre_Verdict::Fail(format!(
981	            "retriever canonical RBRA still present after divest: {} \
982	             (BBAAN divest-deletes-production-RBRA contract violated)",
983	            retriever_canonical.display()
984	        ));
985	    }
986	
987	    if assay_canonical.exists() {
988	        let _ = std::fs::remove_file(&assay_canonical);
989	    }
990	
991	    rbtdre_Verdict::Pass
992	}
993	
994	// ── Case 4: depot tear-down ──────────────────────────────────
995	
996	/// Case 4 — depot tear-down. Pre-condition: depot exists from case 2. Reads
997	/// moniker from rbrr.env, unmakes the depot (BURE_CONFIRM=skip), re-lists,
998	/// and verifies the depot is absent or in DELETE_REQUESTED state via
999	/// fact-file content read (no stdout-grep).
1000	fn rbtdrp_depot_tear_down(dir: &Path) -> rbtdre_Verdict {
1001	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_tear_down_impl(ctx, dir))
1002	}
1003	
1004	fn rbtdrp_depot_tear_down_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
1005	    let root = ctx.project_root().to_path_buf();
1006	
1007	    let rbrr = root.join(RBTDRP_RBRR_FILE);
1008	    let moniker = match rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_DEPOT_MONIKER) {
1009	        Some(m) if !m.is_empty() => m,
1010	        _ => {
1011	            return rbtdre_Verdict::Fail(
1012	                "case 2 (stand-up) did not run or rbrr.env is missing the moniker \
1013	                 (RBRR_DEPOT_MONIKER is blank)"
1014	                    .to_string(),
1015	            )
1016	        }
1017	    };
1018	
1019	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
1020	        Ok(p) => p,
1021	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
1022	    };
1023	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
1024	
1025	    let unmake = match rbtdrp_invoke_logged(
1026	        ctx,
1027	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
1028	        &[],
1029	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
1030	        dir,
1031	        "unmake",
1032	    ) {
1033	        Ok(r) => r,
1034	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
1035	    };
1036	    if unmake.exit_code != 0 {
1037	        return rbtdre_Verdict::Fail(format!(
1038	            "depot unmake exit {}\n{}",
1039	            unmake.exit_code, unmake.stderr
1040	        ));
1041	    }
1042	
1043	    let list_after = match rbtdrp_invoke_logged(
1044	        ctx,
1045	        RBTDRM_COLOPHON_DEPOT_LIST,
1046	        &[],
1047	        &[],
1048	        dir,
1049	        "list-after",
1050	    ) {
1051	        Ok(r) => r,
1052	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
1053	    };
1054	    if list_after.exit_code != 0 {
1055	        return rbtdre_Verdict::Fail(format!(
1056	            "depot list (after unmake) exit {}\n{}",
1057	            list_after.exit_code, list_after.stderr
1058	        ));
1059	    }
1060	
1061	    let depot_fact_path = list_after
1062	        .burv_output
1063	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
1064	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT));
1065	
1066	    if !depot_fact_path.exists() {
1067	        return rbtdre_Verdict::Pass;
1068	    }
1069	
1070	    let depot_state = match std::fs::read_to_string(&depot_fact_path) {
1071	        Ok(s) => s.trim().to_string(),
1072	        Err(e) => {
1073	            return rbtdre_Verdict::Fail(format!(
1074	                "read depot fact '{}': {}",
1075	                depot_fact_path.display(),
1076	                e
1077	            ))
1078	        }
1079	    };
1080	
1081	    if depot_state == RBTDRP_DELETE_REQUESTED {
1082	        return rbtdre_Verdict::Pass;
1083	    }
1084	
1085	    rbtdre_Verdict::Fail(format!(
1086	        "depot '{}' (project '{}') still present with unexpected state '{}' after unmake \
1087	         (expected absent or '{}')",
1088	        moniker, project_id, depot_state, RBTDRP_DELETE_REQUESTED
1089	    ))
1090	}
1091	
1092	// ── Section registry ─────────────────────────────────────────
1093	
1094	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[
1095	    rbtdre_Section {
1096	        name: "pristine-lifecycle-gate",
1097	        cases: &[case!(rbtdrp_marshal_zero_attestation)],
1098	    },
1099	    rbtdre_Section {
1100	        name: "pristine-lifecycle-arc",
1101	        cases: &[
1102	            case!(rbtdrp_depot_stand_up),
1103	            case!(rbtdrp_sa_cycle),
1104	            case!(rbtdrp_depot_tear_down),
1105	        ],
1106	    },
1107	];
1108

