        cases: CASES,
    }];

    let tmp = rbtdte_make_temp("failfast");
    let result = rbtdre_run_sections(SECTIONS, &RBTDTE_COLORS, true, &tmp).unwrap();
    assert_eq!(result.failed, 1);
    assert_eq!(result.passed, 0);
    let _ = std::fs::remove_dir_all(&tmp);
}

